// src/pages/Login.jsx

import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {

  const nav = useNavigate();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [role, setRole] =
    useState("customer");

  const loginUser = async (e) => {

    e.preventDefault();

    try {

      const res = await axios.post(

        "http://localhost:5000/api/auth/login",

        {
          email,
          password,
          role
        }
      );

      localStorage.setItem(

        "user",

        JSON.stringify(res.data.user)

      );

      if (role === "customer") {

        nav("/customer-dashboard");

      } else {

        nav("/labour-dashboard");

      }

    } catch (err) {

      alert("Invalid Credentials");

    }
  };

  return (

    <div style={styles.page}>

      {/* LEFT SIDE */}
      <div style={styles.left}>

        <div style={styles.overlay}></div>

        <div style={styles.leftContent}>

          <div style={styles.badge}>
            Trusted Daily Worker Platform
          </div>

          <h1 style={styles.title}>
            Welcome Back to
            <span style={styles.orange}>
              {" "}DailyMajdoor
            </span>
          </h1>

          <p style={styles.subtitle}>
            Hire skilled workers near your
            location quickly, safely and
            easily with modern worker hiring.
          </p>

        </div>

      </div>

      {/* RIGHT SIDE */}
      <div style={styles.right}>

        <div style={styles.card}>

          <div style={styles.logoCircle}>
            D
          </div>

          <h1 style={styles.logo}>
            Login
          </h1>

          <p style={styles.subtext}>
            Access your account
          </p>

          <form onSubmit={loginUser}>

            <select
              style={styles.input}
              value={role}
              onChange={(e) =>
                setRole(e.target.value)
              }
            >

              <option value="customer">
                Customer
              </option>

              <option value="labour">
                Labour
              </option>

            </select>

            <input
              type="email"
              placeholder="Enter Email"
              style={styles.input}
              value={email}
              onChange={(e) =>
                setEmail(e.target.value)
              }
            />

            <input
              type="password"
              placeholder="Enter Password"
              style={styles.input}
              value={password}
              onChange={(e) =>
                setPassword(e.target.value)
              }
            />

            <button style={styles.button}>
              Login Now
            </button>

          </form>

          <p style={styles.bottomText}>

            Don't have an account?

            <span
              style={styles.link}
              onClick={() =>
                nav("/register")
              }
            >
              Register
            </span>

          </p>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    display: "flex",
    fontFamily: "Arial",
    background: "#0f172a"
  },

  /* LEFT */

  left: {
    width: "55%",
    position: "relative",
    backgroundImage:
      "url('https://images.unsplash.com/photo-1504307651254-35680f356dfd?q=80&w=1400&auto=format&fit=crop')",
    backgroundSize: "cover",
    backgroundPosition: "center",
    display: "flex",
    alignItems: "center",
    padding: "80px"
  },

  overlay: {
    position: "absolute",
    inset: 0,
    background:
      "linear-gradient(to right, rgba(15,23,42,0.9), rgba(15,23,42,0.65))"
  },

  leftContent: {
    position: "relative",
    zIndex: 2,
    color: "white",
    maxWidth: "520px"
  },

  badge: {
    display: "inline-block",
    background: "rgba(255,255,255,0.08)",
    border: "1px solid rgba(255,255,255,0.1)",
    padding: "12px 22px",
    borderRadius: "30px",
    marginBottom: "28px",
    color: "#f97316",
    fontWeight: "bold",
    backdropFilter: "blur(10px)"
  },

  title: {
    fontSize: "64px",
    lineHeight: "76px",
    marginBottom: "24px",
    fontWeight: "800"
  },

  orange: {
    color: "#f97316"
  },

  subtitle: {
    fontSize: "20px",
    lineHeight: "36px",
    color: "#cbd5e1"
  },

  /* RIGHT */

  right: {
    width: "45%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "40px"
  },

  card: {
    width: "420px",
    background: "rgba(255,255,255,0.08)",
    border: "1px solid rgba(255,255,255,0.08)",
    padding: "45px",
    borderRadius: "28px",
    backdropFilter: "blur(16px)",
    boxShadow: "0 20px 40px rgba(0,0,0,0.3)"
  },

  logoCircle: {
    width: "58px",
    height: "58px",
    borderRadius: "18px",
    background: "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontWeight: "bold",
    fontSize: "22px",
    margin: "0 auto 24px auto"
  },

  logo: {
    textAlign: "center",
    color: "white",
    marginBottom: "10px",
    fontSize: "34px"
  },

  subtext: {
    textAlign: "center",
    color: "#cbd5e1",
    marginBottom: "35px",
    fontSize: "16px"
  },

  input: {
    width: "100%",
    padding: "16px",
    marginBottom: "18px",
    borderRadius: "14px",
    border: "1px solid rgba(255,255,255,0.08)",
    background: "rgba(255,255,255,0.08)",
    color: "white",
    boxSizing: "border-box",
    outline: "none",
    fontSize: "15px"
  },

  button: {
    width: "100%",
    padding: "16px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    border: "none",
    borderRadius: "14px",
    cursor: "pointer",
    fontWeight: "bold",
    fontSize: "16px",
    marginTop: "10px",
    boxShadow:
      "0 10px 25px rgba(249,115,22,0.35)"
  },

  bottomText: {
    textAlign: "center",
    marginTop: "28px",
    color: "#cbd5e1"
  },

  link: {
    color: "#f97316",
    marginLeft: "6px",
    cursor: "pointer",
    fontWeight: "bold"
  }

};
